import React, { useState } from 'react';
import Header from './components/Header';
import CheckPage from './components/CheckPage';
import LogsPage from './components/LogsPage';

export default function App() {
  const [page, setPage] = useState('check'); // 'check' | 'logs'

  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column' }}>
      <Header page={page} setPage={setPage} />
      <main style={{ flex: 1, padding: '2rem 1rem', maxWidth: 900, margin: '0 auto', width: '100%' }}>
        {page === 'check' ? <CheckPage /> : <LogsPage />}
      </main>
      <footer style={{ textAlign: 'center', padding: '1.5rem', color: 'var(--text-dim)', fontFamily: 'var(--font-mono)', fontSize: '0.75rem', borderTop: '1px solid var(--border)' }}>
        AI ASSISTANT FIREWALL v1.0 · SECURE LAYER ACTIVE
      </footer>
    </div>
  );
}
